class Solution:
    def shortestDistanceAfterQueries(self, n, queries):
        from collections import deque, defaultdict
        adj = defaultdict(list)
        for i in range(n - 1):
            adj[i].append(i + 1)
        ans = []
        for u, v in queries:
            adj[u].append(v)
            dist = [-1] * n
            dist[0] = 0
            q = deque([0])
            while q:
                node = q.popleft()
                if node == n - 1:
                    break
                for nxt in adj[node]:
                    if dist[nxt] == -1:
                        dist[nxt] = dist[node] + 1
                        q.append(nxt)
            ans.append(dist[n - 1])
        return ans

