class Solution:
    def shortestDistanceAfterQueries(self, n, queries):
        from collections import defaultdict
        edges_from = defaultdict(list)
        for i in range(n - 1):
            edges_from[i].append(i + 1)
        ans = []
        for u, v in queries:
            edges_from[u].append(v)
            dist = [float('inf')] * n
            dist[0] = 0
            for node in range(n):
                if dist[node] == float('inf'):
                    continue
                for nxt in edges_from[node]:
                    if dist[node] + 1 < dist[nxt]:
                        dist[nxt] = dist[node] + 1
            ans.append(dist[n - 1])
        return ans

