var shortestDistanceAfterQueries = function(n, queries) {
    const edgesFrom = Array.from({ length: n }, () => []);
    for (let i = 0; i < n - 1; i++) edgesFrom[i].push(i + 1);
    const ans = [];
    for (const [u, v] of queries) {
        edgesFrom[u].push(v);
        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;
        for (let node = 0; node < n; node++) {
            if (dist[node] === Infinity) continue;
            for (const nxt of edgesFrom[node]) {
                if (dist[node] + 1 < dist[nxt]) dist[nxt] = dist[node] + 1;
            }
        }
        ans.push(dist[n - 1]);
    }
    return ans;
};
